class Solution {
public:
  int solve(vector<int>& freq, int n) {
    sort(freq.begin(), freq.end(), greater<int>());
    int result = 0;
    for (int i = 0; i < n; i += 2) {
      if (i + 1 < n) result += 2;
      else result++;
    }
    return min(result, n);
  }
};
